#include <vector>
#include <iostream>

using namespace std;

class UnionFind {
public:
    vector<int> parent;
    vector<int> rank;
    UnionFind(int n) {
        parent.resize(n);
        rank.resize(n, 0);
        for (int i = 0; i < n; i++) {
            parent[i] = i;
        }
    }

    int find(int x) {
        if (parent[x] != x) {
            parent[x] = find(parent[x]);
        }
        return parent[x];
    }

    void unite(int x, int y) {
        x = find(x);
        y = find(y);
        if (x == y) 
            return;
        if (rank[x] < rank[y]) {
            parent[x] = y;
        } else if (rank[x] > rank[y]) {
            parent[y] = x;
        } else {
            parent[y] = x;
            rank[x]++;
        }
    }

    bool connected(int x, int y) {
        return find(x) == find(y);
    }
};

long long solve(vector<long long> nums_ll) {
    vector<int> nums;
    for (auto x : nums_ll) {
        nums.push_back((int)x);
    }
    int n = nums.size();
    bool sorted = true;
    for (int i = 0; i < n; i++) {
        if (nums[i] != i) {
            sorted = false;
            break;
        }
    }
    if (sorted) {
        return 0;
    }

    vector<int> pos(n);
    for (int i = 0; i < n; i++) {
        pos[nums[i]] = i;
    }

    vector<int> idx_vis(n, false);
    vector<vector<int>> cycles;
    for (int i = 0; i < n; i++) {
        if (idx_vis[i]) 
            continue;
        int cur = i;
        vector<int> cycle;
        while (!idx_vis[cur]) {
            idx_vis[cur] = 1;
            cycle.push_back(nums[cur]);
            cur = pos[nums[cur]];
        }
        cycles.push_back(cycle);
    }

    int candidate = 0;
    const int BIT = 21;
    int M = 1 << BIT;

    for (int bit = BIT - 1; bit >= 0; --bit) {
        int test = candidate | (1 << bit);
        int available_mask = (1 << BIT) - 1 - test;
        UnionFind uf(n + M);
        vector<bool> has_pattern(M, false);

        for (int value = 0; value < n; ++value) {
            if ((value & test) != test) 
                continue;
            int a = value & available_mask;
            if (a < M) {
                has_pattern[a] = true;
                uf.unite(value, n + a);
            }
        }

        for (int bit_idx = 0; bit_idx < BIT; ++bit_idx) {
            for (int p = 0; p < M; ++p) {
                if (p & (1 << bit_idx)) {
                    int to = p ^ (1 << bit_idx);
                    if (to < M && has_pattern[p] && has_pattern[to]) {
                        uf.unite(n + p, n + to);
                    }
                }
            }
        }

        bool valid = true;
        for (const vector<int>& cycle : cycles) {
            if (cycle.size() == 1) 
                continue;
            int comp = uf.find(cycle[0]);
            for (int j = 1; j < cycle.size(); ++j) {
                if (!uf.connected(cycle[j], comp)) {
                    valid = false;
                    break;
                }
            }
            if (!valid) 
                break;
        }

        if (valid) {
            candidate = test;
        }
    }
    return candidate;
}
