#include <vector>
#include <algorithm>
using namespace std;

struct DSU {
    vector<int> parent;
    DSU(int n) : parent(n) {
        for (int i = 0; i < n; i++) {
            parent[i] = i;
        }
    }
    int find(int x) {
        if (parent[x] != x) {
            parent[x] = find(parent[x]);
        }
        return parent[x];
    }
    void unite(int x, int y) {
        int rx = find(x), ry = find(y);
        if (rx != ry) {
            parent[rx] = ry;
        }
    }
};

long long solve(vector<long long> nums) {
    int n = nums.size();
    vector<long long> sorted_nums = nums;
    sort(sorted_nums.begin(), sorted_nums.end());
    if (nums == sorted_nums) {
        return 0;
    }

    vector<bool> visited(n, false);
    vector<vector<int>> cycles;
    for (int i = 0; i < n; i++) {
        if (visited[i]) continue;
        vector<int> cycle;
        int j = i;
        while (!visited[j]) {
            visited[j] = true;
            cycle.push_back(j);
            j = nums[j];
        }
        if (cycle.size() > 1) {
            cycles.push_back(cycle);
        }
    }

    if (cycles.empty()) {
        return 0;
    }

    int max_bit = 0;
    while ((1LL << max_bit) < n) {
        max_bit++;
    }

    long long candidate = 0;
    for (int b = max_bit - 1; b >= 0; b--) {
        long long new_candidate = candidate | (1LL << b);

        DSU dsu(n);
        vector<bool> exists(n, false);

        for (int i = 0; i < n; i++) {
            if ((nums[i] & new_candidate) != new_candidate) {
                continue;
            }
            exists[i] = true;
        }

        for (int i = 0; i < n; i++) {
            if (!exists[i]) continue;
            int a = i;
            int mask = a & ~new_candidate;
            for (int bit = 0; bit < max_bit; bit++) {
                if (!(mask & (1 << bit))) continue;
                int comp = (new_candidate) | (mask & ~(1 << bit));
                if (comp < n && exists[comp]) {
                    dsu.unite(a, comp);
                }
            }
        }

        bool valid = true;
        for (const vector<int>& cycle : cycles) {
            int root = -1;
            for (int idx : cycle) {
                if ((nums[idx] & new_candidate) != new_candidate) {
                    valid = false;
                    break;
                }
                int r = dsu.find(idx);
                if (root == -1) {
                    root = r;
                } else if (root != r) {
                    valid = false;
                }
            }
            if (!valid) break;
        }

        if (valid) {
            candidate = new_candidate;
        }
    }

    return candidate;
}
