    long long max_possible_k = 0;
    for (long long k = 0; k < n; k++) {
        if (k > (1LL<<20)) break;
        bool valid = true;
        for (int i = 0; i < n; i++) {
            if ((i & k) != k) {
                if (nums[i] != i) {
                    valid = false;
                    break;
                }
            }
        }
        if (!valid) continue;

        vector<int> k_containing;
        unordered_map<long long, int> comp_id;
        for (int i = 0; i < n; i++) {
            if ((i & k) == k) {
                k_containing.push_back(i);
            }
        }

        if (k_containing.size() == 0) {
            max_possible_k = max(max_possible_k, k);
            continue;
        }

        vector<long long> present_masks;
        for (int val : k_containing) {
            long long a = val - k;
            present_masks.push_back(a);
            comp_id[a] = 0;
        }

        sort(present_masks.begin(), present_masks.end());
        present_masks.erase(unique(present_masks.begin(), present_masks.end()), present_masks.end());
        int num_masks = present_masks.size();
        for (int i = 0; i < num_masks; i++) {
            comp_id[present_masks[i]] = i;
        }

        DSU dsu(num_masks);
        bool has_zero = false;
        for (long long a : present_masks) {
            if (a == 0) {
                has_zero = true;
                break;
            }
        }
        if (has_zero) {
            for (int i = 0; i < num_masks; i++) {
                dsu.unite(i, comp_id[0]);
            }
        }

        for (int b = 0; b < 20; b++) {
            long long bit_mask = 1LL << b;
            int count_with_bit = 0;
            long last_mask = -1;
            for (long long mask : present_masks) {
                if (mask & bit_mask) {
                    count_with_bit++;
                    last_mask = mask;
                }
            }
            if (count_with_bit == 1) {
                for (long long mask : present_masks) {
                    if ((mask & bit_mask) && mask == last_mask) {
                        continue;
                    }
                    if ((mask & bit_mask) == 0) {
                        dsu.unite(comp_id[last_mask], comp_id[mask]);
                    }
                }
            }
        }

        valid = true;
        for (int i : k_containing) {
            long long a1 = i - k;
            long long a2 = nums[i] - k;
            if (a1 < 0 || a2 < 0) {
